let bcv_4d = 0;
let paralelo = 0;
let difcamb = 0;
let web_rate = null;

// Scraping always takes precedence for BCV (Source of truth)
const reqWeb = this.helpers.httpRequest({ url: "https://www.bcv.org.ve/", method: "GET", timeout: 30000, rejectUnauthorized: false });
const reqOficial = this.helpers.httpRequest({ url: "https://ve.dolarapi.com/v1/dolares/oficial", method: "GET", timeout: 30000 });
const reqParalelo = this.helpers.httpRequest({ url: "https://ve.dolarapi.com/v1/dolares/paralelo", method: "GET", timeout: 30000 });

const results = await Promise.allSettled([reqWeb, reqOficial, reqParalelo]);

let bcvHtml = results[0].status === 'fulfilled' ? results[0].value : "";
let oficialApi = results[1].status === 'fulfilled' ? (typeof results[1].value === 'string' ? JSON.parse(results[1].value) : results[1].value) : {};
let apiParalelo = results[2].status === 'fulfilled' ? (typeof results[2].value === 'string' ? JSON.parse(results[2].value) : results[2].value) : {};

if (apiParalelo.promedio || apiParalelo.price) paralelo = apiParalelo.promedio || apiParalelo.price;

let api_val = oficialApi.promedio || oficialApi.price || 0;
if (bcvHtml && typeof bcvHtml === 'string') {
    let rateMatch = bcvHtml.match(/id\s*=\s*['"]dolar['"][\s\S]*?<strong[^>]*>([\d,.]+)/i);
    if (rateMatch && rateMatch[1]) {
        let parsed = parseFloat(rateMatch[1].trim().replace(',', '.'));
        if (!isNaN(parsed)) web_rate = parsed;
    }
}

bcv_4d = web_rate || api_val || 0;
if (!bcv_4d && !paralelo) throw new Error("Tasas nulas en todas las ramas paralelas.");
if (bcv_4d > 0 && paralelo > 0) difcamb = parseFloat((paralelo / bcv_4d).toFixed(6));

let recentDatesRecords = [];
try {
    let recent = $('Get Recent Dates').all();
    if (recent) recentDatesRecords = recent.map(i => i.json);
} catch(e) {}

let getDbRecord = (dateStr) => {
    return recentDatesRecords.find(r => String(r.fecha).split('T')[0] === dateStr);
};

let sql = "";
let vzlaTime = new Date(new Date().toLocaleString("en-US", {timeZone: "America/Caracas"}));
let hour = vzlaTime.getHours();
let todayStr = vzlaTime.toISOString().split('T')[0];
let currentDayOfWeek = vzlaTime.getDay(); 

let datesToUpdateBCV = [];
let datesToUpdateParalelo = [todayStr]; 

if (hour >= 16) {
    let tomorrow = new Date(vzlaTime); tomorrow.setDate(tomorrow.getDate() + 1);
    let tomorrowStr = tomorrow.toISOString().split('T')[0];
    datesToUpdateBCV.push(tomorrowStr);

    if (currentDayOfWeek === 5) { 
        let sunday = new Date(tomorrow); sunday.setDate(sunday.getDate() + 1);
        let monday = new Date(tomorrow); monday.setDate(monday.getDate() + 2);
        datesToUpdateBCV.push(sunday.toISOString().split('T')[0]);
        datesToUpdateBCV.push(monday.toISOString().split('T')[0]);
    }

    // Strict consistency validation FOR ALL DAYS
    // If the rate pulled is identical to the rate of the previous banking day, 
    // it means the new rate hasn't been published yet (delayed).
    // We abort pushing to tomorrow until it changes (unless it's a holiday).
    let todayRecord = getDbRecord(todayStr);
    if (todayRecord && todayRecord.dolarbcv) {
        // Find the previous day's record (skip weekends to find previous banking day)
        let daysToSubtract = (currentDayOfWeek === 1) ? 3 : 1; // If Monday, compare to Friday
        let prevDay = new Date(vzlaTime.getTime() - daysToSubtract*86400000).toISOString().split('T')[0];
        let prevRecord = getDbRecord(prevDay);

        if (todayRecord.dolarbcv !== prevRecord?.dolarbcv) {
            // Not a holiday. The rate HAS changed between prev day and today.
            // If bcv_4d equals today's OLD rate, it hasn't updated yet!
            if (Math.abs(bcv_4d - todayRecord.dolarbcv) < 0.0001) {
                datesToUpdateBCV = []; 
            }
        }
    }
} else {
    datesToUpdateBCV.push(todayStr);
    if (currentDayOfWeek === 6) { 
        let sunday = new Date(vzlaTime); sunday.setDate(sunday.getDate() + 1);
        let monday = new Date(vzlaTime); monday.setDate(monday.getDate() + 2);
        datesToUpdateBCV.push(sunday.toISOString().split('T')[0]);
        datesToUpdateBCV.push(monday.toISOString().split('T')[0]);
    } else if (currentDayOfWeek === 0) { 
        let monday = new Date(vzlaTime); monday.setDate(monday.getDate() + 1);
        datesToUpdateBCV.push(monday.toISOString().split('T')[0]);
    }
}

let allDatesSet = new Set([...datesToUpdateBCV, ...datesToUpdateParalelo]);

for (let dateStr of allDatesSet) {
    let applyBcv = datesToUpdateBCV.includes(dateStr) ? bcv_4d : 0;
    let applyPar = datesToUpdateParalelo.includes(dateStr) ? paralelo : 0;
    let applyDif = (applyBcv > 0 && applyPar > 0) ? parseFloat((applyPar / applyBcv).toFixed(6)) : null;

    if (applyBcv > 0 || applyPar > 0) {
        let isWeekend = datesToUpdateBCV.includes(dateStr) && !datesToUpdateParalelo.includes(dateStr);
        let fuenteTag = isWeekend ? 'api_weekend' : 'api';

        sql += `
IF EXISTS (SELECT 1 FROM dolartoday WHERE CAST(fecha AS DATE) = '${dateStr}' AND fuente NOT IN ('manual', 'bot_trigger'))
BEGIN
    UPDATE dolartoday SET 
`;
        let sets = [];
        if (applyPar > 0) sets.push(`Dolartoday = ${applyPar}`);
        if (applyBcv > 0) sets.push(`dolarbcv = ${applyBcv}`);
        if (applyDif !== null) sets.push(`DifCamb = ${applyDif}`);
        sets.push(`pendiente = 0`);
        sets.push(`_hora = dbo.sfAA_HoraClarion(GETDATE())`);

        sql += `        ${sets.join(", ")}
    WHERE id = (SELECT TOP 1 id FROM dolartoday WHERE CAST(fecha AS DATE) = '${dateStr}' AND fuente NOT IN ('manual', 'bot_trigger') ORDER BY id DESC);
END
ELSE
BEGIN
    INSERT INTO dolartoday (fecha, _fecha, _hora, Dolartoday, dolarbcv, pendiente, DifCamb, fuente) 
    VALUES ('${dateStr}', dbo.sfAA_FechaClarion('${dateStr}'), dbo.sfAA_HoraClarion(GETDATE()), ${applyPar > 0 ? applyPar : "NULL"}, ${applyBcv > 0 ? applyBcv : "NULL"}, 0, ${applyDif !== null ? applyDif : "NULL"}, '${fuenteTag}');
END
`;
    }
}

sql += `DECLARE @targetDate DATE = '${todayStr}';\n`;
if (bcv_4d > 0) {
    sql += `UPDATE SACONF SET Factor = ${bcv_4d}, FactorM = ${bcv_4d};\n`;
    sql += `UPDATE SATARJ SET Monto = ${bcv_4d} WHERE TipoIns = 0;\n`;
}

return { json: { sql: sql, status: "OK", bcv_4d: bcv_4d, paralelo: paralelo } };
